cis-1-2-rules.description:
Map of parameters for interpolation within the YAML config templates

For example, to override the maxCredentialUsageAge parameter in the access-keys-rotated.yaml rule, you would specify
the following:

parameter_overrides = {
  "access-keys-rotated" : { maxCredentialUsageAge : "120" }
}

root.type:
map(object({
    description         = string
    lambda_function_arn = string
    input_parameters    = optional(any, {})
    source_identifier   = optional(string, null)
    evaluation_mode     = optional(string, null)
    scope = optional(object({
      compliance_resource_types = optional(list(string), [])
    }), null)
    tags    = optional(map(string), {})
    enabled = bool
  }))

map(object({
    description               = string
    policy                    = optional(string, null)
    policy_runtime            = optional(string, "guard-2.x.x")
    enable_debug_log_delivery = optional(bool, false)
    evaluation_mode           = optional(string, null)
    input_parameters          = optional(any, {})
    scope = optional(object({
      compliance_resource_types = optional(list(string), [])
    }), null)
    tags    = optional(map(string), {})
    enabled = bool
  }))

object({
    recording_frequency = string
    recording_mode_override = optional(object({
      description         = string
      recording_frequency = string
      resource_types      = list(string)
    }))
